const listCVEsFiltered = `-- name: ListCVEsFiltered :many
SELECT c.id, c.tenant_id, c.cve_id, c.severity, c.description, c.published_at, c.created_at, c.updated_at, c.cvss_v3_score, c.cvss_v3_vector, c.cisa_kev_due_date, c.exploit_available, c.nvd_last_modified, c.attack_vector, c.external_references, c.cwe_id, c.source,
       (SELECT count(*) FROM endpoint_cves ec WHERE ec.cve_id = c.id AND ec.tenant_id = c.tenant_id)::int AS affected_endpoint_count,
       EXISTS(SELECT 1 FROM patch_cves pc WHERE pc.cve_id = c.id AND pc.tenant_id = c.tenant_id) AS patch_available,
       (SELECT count(*)::int FROM patch_cves pc WHERE pc.cve_id = c.id AND pc.tenant_id = c.tenant_id) AS patch_count
FROM cves c
WHERE c.tenant_id = $1
  AND ($2::text = '' OR c.severity = $2)
  AND ($3::text = '' OR c.cisa_kev_due_date IS NOT NULL)
  AND ($4::text = '' OR c.exploit_available = ($4 = 'true'))
  AND ($5::text = '' OR c.attack_vector = $5)
  AND ($6::text = '' OR c.cve_id ILIKE '%' || $6 || '%')
  AND ($7::timestamptz IS NULL OR c.published_at >= $7)
  AND ($8::text = '' OR ($8 = 'true' AND EXISTS(SELECT 1 FROM patch_cves pc2 WHERE pc2.cve_id = c.id AND pc2.tenant_id = c.tenant_id)) OR ($8 = 'false' AND NOT EXISTS(SELECT 1 FROM patch_cves pc3 WHERE pc3.cve_id = c.id AND pc3.tenant_id = c.tenant_id)))
  AND (
    $9::timestamptz IS NULL
    OR (c.created_at, c.id) < ($9, $10::uuid)
  )
ORDER BY c.created_at DESC, c.id DESC
LIMIT $11
`

