const listPatchesFiltered = `-- name: ListPatchesFiltered :many
WITH patch_cve_stats AS (
    SELECT pc.patch_id,
           count(*)::int AS cve_count,
           COALESCE(MAX(c.cvss_v3_score), 0)::float8 AS highest_cvss_score
    FROM patch_cves pc
    JOIN cves c ON c.id = pc.cve_id AND c.tenant_id = pc.tenant_id
    WHERE pc.tenant_id = $1
    GROUP BY pc.patch_id
),
patch_remediation AS (
    SELECT pc.patch_id,
           CASE WHEN count(*) = 0 THEN 0
                ELSE (count(*) FILTER (WHERE ec.status = 'patched') * 100 / count(*))::int
           END AS remediation_pct,
           count(DISTINCT ec.endpoint_id) FILTER (WHERE ec.status = 'patched')::int AS endpoints_deployed_count,
           count(DISTINCT ec.endpoint_id)::int AS affected_endpoint_count
    FROM patch_cves pc
    JOIN endpoint_cves ec ON ec.cve_id = pc.cve_id AND ec.tenant_id = pc.tenant_id
    WHERE pc.tenant_id = $1
    GROUP BY pc.patch_id
)
SELECT p.id, p.tenant_id, p.name, p.version, p.severity, p.os_family, p.status, p.created_at, p.updated_at, p.os_distribution, p.package_url, p.checksum_sha256, p.source_repo, p.description, p.released_at, p.package_name, p.installer_type, p.silent_args, p.deleted_at, p.hub_catalog_id,
       COALESCE(pcs.cve_count, 0)::int AS cve_count,
       COALESCE(pcs.highest_cvss_score, 0)::float8 AS highest_cvss_score,
       COALESCE(pr.remediation_pct, 0)::int AS remediation_pct,
       COALESCE(pr.endpoints_deployed_count, 0)::int AS endpoints_deployed_count,
       COALESCE(pr.affected_endpoint_count, 0)::int AS affected_endpoint_count
FROM patches p
LEFT JOIN patch_cve_stats pcs ON pcs.patch_id = p.id
LEFT JOIN patch_remediation pr ON pr.patch_id = p.id
WHERE p.tenant_id = $1
  AND p.deleted_at IS NULL
  AND ($2::text = '' OR p.severity = $2)
  AND ($3::text = '' OR p.os_family = $3)
  AND ($4::text = '' OR p.os_distribution = $4)
  AND ($5::text = '' OR p.status = $5)
  AND ($6::text = '' OR p.name ILIKE '%' || $6 || '%')
  AND (
    $7::timestamptz IS NULL
    OR (p.created_at, p.id) < ($7, $8::uuid)
  )
ORDER BY
  CASE WHEN $9::text = 'name'     AND $10::text = 'asc'  THEN p.name END ASC NULLS LAST,
  CASE WHEN $9::text = 'name'     AND $10::text = 'desc' THEN p.name END DESC NULLS LAST,
  CASE WHEN $9::text = 'severity' AND $10::text = 'asc'  THEN CASE p.severity WHEN 'critical' THEN 1 WHEN 'high' THEN 2 WHEN 'medium' THEN 3 WHEN 'low' THEN 4 ELSE 5 END END ASC,
  CASE WHEN $9::text = 'severity' AND $10::text = 'desc' THEN CASE p.severity WHEN 'critical' THEN 1 WHEN 'high' THEN 2 WHEN 'medium' THEN 3 WHEN 'low' THEN 4 ELSE 5 END END DESC,
  CASE WHEN $9::text = 'cvss'     AND $10::text = 'asc'  THEN COALESCE(pcs.highest_cvss_score, 0) END ASC,
  CASE WHEN $9::text = 'cvss'     AND $10::text = 'desc' THEN COALESCE(pcs.highest_cvss_score, 0) END DESC,
  CASE WHEN $9::text = 'cves'     AND $10::text = 'asc'  THEN COALESCE(pcs.cve_count, 0) END ASC,
  CASE WHEN $9::text = 'cves'     AND $10::text = 'desc' THEN COALESCE(pcs.cve_count, 0) END DESC,
  CASE WHEN $9::text = 'affected' AND $10::text = 'asc'  THEN COALESCE(pr.affected_endpoint_count, 0) END ASC,
  CASE WHEN $9::text = 'affected' AND $10::text = 'desc' THEN COALESCE(pr.affected_endpoint_count, 0) END DESC,
  p.created_at DESC, p.id DESC
LIMIT $11
`

